func (s *DynamicProtoService) validateProtoDefinition(protoDef string) error {
	if len(protoDef) == 0 {
		return errors.New("empty proto definition")
	}

	if len(protoDef) > maxProtoSize {
		return errors.New("proto definition too large")
	}

	if strings.Contains(protoDef, "import") {
		return errors.New("import statements not allowed")
	}

	if strings.Contains(protoDef, "option") && !strings.Contains(protoDef, "option go_package") {
		return errors.New("only go_package option allowed")
	}

	lines := strings.Split(protoDef, "\n")
	var inMessage bool
	var messageDepth int
	var fieldCount int

	for _, line := range lines {
		line = strings.TrimSpace(line)

		if strings.HasPrefix(line, "syntax") {
			if !strings.Contains(line, `"proto3"`) {
				return errors.New("only proto3 syntax allowed")
			}
		}

		if strings.HasPrefix(line, "package") {
			pkg := strings.TrimSpace(strings.TrimSuffix(strings.TrimPrefix(line, "package"), ";"))
			if len(pkg) > maxPackageNameLen || !packageNameRegex.MatchString(pkg) {
				return errors.New("invalid package name")
			}
		}

		if strings.HasPrefix(line, "message") {
			inMessage = true
			messageDepth++
			if messageDepth > maxNestingDepth {
				return errors.New("message nesting too deep")
			}
			parts := strings.Fields(line)
			if len(parts) >= 2 {
				msgName := strings.TrimSuffix(parts[1], "{")
				if len(msgName) > maxMessageNameLen || !messageNameRegex.MatchString(msgName) {
					return errors.New("invalid message name")
				}
			}
		}

		if strings.Contains(line, "}") && inMessage {
			messageDepth--
			if messageDepth == 0 {
				inMessage = false
				fieldCount = 0
			}
		}

		if inMessage && !strings.HasPrefix(line, "message") && !strings.HasPrefix(line, "}") && len(line) > 0 && !strings.HasPrefix(line, "//") {
			fieldCount++
			if fieldCount > maxFieldCount {
				return errors.New("too many fields in message")
			}

			parts := strings.Fields(line)
			if len(parts) >= 2 {
				fieldType := parts[0]
				if !allowedTypes[fieldType] && !messageNameRegex.MatchString(fieldType) {
					return errors.New("invalid field type: " + fieldType)
				}

				fieldName := parts[1]
				if !fieldNameRegex.MatchString(fieldName) {
					return errors.New("invalid field name: " + fieldName)
				}
			}
		}
	}

	dangerousPatterns := []string{
		"../", "..", "~", "$", "`", "|", "&", ";", ">", "<",
		"exec", "system", "eval", "shell",
	}
	lowerProto := strings.ToLower(protoDef)
	for _, pattern := range dangerousPatterns {
		if strings.Contains(lowerProto, pattern) {
			return errors.New("potentially dangerous content detected")
		}
	}

	return nil
}

func (s *DynamicProtoService) compileProtoSecurely(ctx context.Context, protoDef, clientID string) (*CompileProtoResponse, error) {
	protoHash := s.hashProto(protoDef)
	clientDir := filepath.Join(s.workDir, clientID, protoHash)

	if err := os.MkdirAll(clientDir, 0700); err != nil {
		return nil, err
	}
	defer os.RemoveAll(clientDir)

	protoFile := filepath.Join(clientDir, "schema.proto")
	if err := os.WriteFile(protoFile, []byte(protoDef), 0600); err != nil {
		return nil, err
	}

	outputDir := filepath.Join(clientDir, "output")
	if err := os.MkdirAll(outputDir, 0700); err != nil {
		return nil, err
	}

	protocPath, err := exec.LookPath("protoc")
	if err != nil {
		return nil, errors.New("protoc not found in PATH")
	}

	timeoutCtx, cancel := context.WithTimeout(ctx, compilationTimeout)
	defer cancel()

	cmd := exec.CommandContext(timeoutCtx, protocPath,
		fmt.Sprintf("--proto_path=%s", clientDir),
		fmt.Sprintf("--descriptor_set_out=%s", filepath.Join(outputDir, "descriptor.pb")),
		"--include_imports",
		"--include_source_info",
		protoFile,
	)

	cmd.Env = []string{
		"PATH=" + filepath.Dir(protocPath),
		"HOME=/tmp",
	}

	cmd.Dir = clientDir

	output, err := cmd.CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("protoc execution failed: %v, output: %s", err, string(output))
	}

	descriptorFile := filepath.Join(outputDir, "descriptor.pb")
	descriptorData, err := os.ReadFile(descriptorFile)
	if err != nil {
		return nil, err
	}

	fds := &descriptorpb.FileDescriptorSet{}
	if err := proto.Unmarshal(descriptorData, fds); err != nil {
		return nil, err
	}

	if len(fds.File) == 0 {
		return nil, errors.New("no file descriptors generated")
	}

	fileDesc := fds.File[0]
	if fileDesc.GetSyntax() != "proto3" {
		return nil, errors.New("only proto3 syntax supported")
	}

	return &CompileProtoResponse{
		Success:        true,
		DescriptorSet:  descriptorData,
		PackageName:    fileDesc.GetPackage(),
		MessageNames:   s.extractMessageNames(fileDesc),
		CompilationLog: "Compilation successful",
	}, nil
}

