func main() {
	workDir := os.Getenv("WORK_DIR")
	if workDir == "" {
		workDir = "/tmp/proto_compiler"
	}

	apiKeys := []string{
		os.Getenv("API_KEY_1"),
		os.Getenv("API_KEY_2"),
	}

	validKeys := []string{}
	for _, key := range apiKeys {
		if len(key) >= 32 {
			validKeys = append(validKeys, key)
		}
	}

	if len(validKeys) == 0 {
		log.Fatal("No valid API keys configured (minimum 32 characters)")
	}

	service, err := NewDynamicProtoService(workDir, validKeys)
	if err != nil {
		log.Fatalf("Failed to create service: %v", err)
	}

	certFile := os.Getenv("TLS_CERT_FILE")
	keyFile := os.Getenv("TLS_KEY_FILE")

	if certFile == "" || keyFile == "" {
		log.Fatal("TLS_CERT_FILE and TLS_KEY_FILE must be set")
	}

	creds, err := credentials.NewServerTLSFromFile(certFile, keyFile)
	if err != nil {
		log.Fatalf("Failed to load TLS credentials: %v", err)
	}

	grpcServer := grpc.NewServer(
		grpc.Creds(creds),
		grpc.MaxRecvMsgSize(maxProtoSize),
		grpc.MaxSendMsgSize(10*1024*1024),
	)

	RegisterDynamicProtoServiceServer(grpcServer, service)

	port := os.Getenv("PORT")
	if port == "" {
		port = "50051"
	}

	listener, err := net.Listen("tcp", ":"+port)
	if err != nil {
		log.Fatalf("Failed to listen: %v", err)
	}

	log.Printf("Secure gRPC server listening on port %s with TLS", port)
	if err := grpcServer.Serve(listener); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

